public class PackageParser {

    // 解析单条包裹数据
    public void parsePackage(String data) throws PackageException {
        if (data == null || data.trim().isEmpty()) {
            throw new PackageException("包裹数据不能为空");
        }

        // 示例：约定包裹数据中必须包含“-”作为格式标记
